{"code":"import json

businesses = locals()['var_function-call-9243428275641800475']
ratings = locals()['var_function-call-1083418170745779414']

rating_map = {}
for r in ratings:
    bid = r['business_ref'].replace('businessref_', 'businessid_')
    rating_map[bid] = float(r['avg_rating'])

# Expanded keywords
keywords = [
    "including ",
    "services in ",
    "destination for ",
    "fields of ",
    "products in ",
    "consisting of "
]

category_stats = {} 

def extract_categories(desc):
    best_keyword = None
    best_index = -1

    for kw in keywords:
        idx = desc.rfind(kw)
        if idx > best_index:
            best_index = idx
            best_keyword = kw

    if best_keyword:
        cats_str = desc[best_index + len(best_keyword):]
        if cats_str.endswith('.'):
            cats_str = cats_str[:-1]

        parts = cats_str.split(',')
        cats = []
        for p in parts:
            p = p.strip()
            if p.startswith('and '):
                p = p[4:].strip()
            if p:
                cats.append(p)
        return cats
    return []

for b in businesses:
    bid = b['business_id']
    desc = b.get('description', '')
    cats = extract_categories(desc)
    rating = rating_map.get(bid)

    if rating is not None and cats:
        for c in cats:
            if c not in category_stats:
                category_stats[c] = {'count': 0, 'total_rating': 0.0}
            category_stats[c]['count'] += 1
            category_stats[c]['total_rating'] += rating

max_count = -1
best_category = None
best_cat_avg_rating = 0.0

# Find max count
# If tie, picking one (the one with higher rating maybe? or just any)
# I'll pick the one with higher rating for tie-breaking stability
for c, stats in category_stats.items():
    if stats['count'] > max_count:
        max_count = stats['count']
        best_category = c
        best_cat_avg_rating = stats['total_rating'] / stats['count']
    elif stats['count'] == max_count:
        # tie breaker
        curr_avg = stats['total_rating'] / stats['count']
        if curr_avg > best_cat_avg_rating:
            best_category = c
            best_cat_avg_rating = curr_avg

result = {
    "best_category": best_category,
    "business_count": max_count,
    "average_rating": best_cat_avg_rating
}

print("__RESULT__:")
print(json.dumps(result))
